// eslint-disable-next-line import/no-anonymous-default-export
export const uaLocale = (number, index) => {
  // 'number' represents the time difference value
  // 'index' indicates the unit index (e.g., 0 for seconds, 1 for minutes, etc.)
  // 'totalSec' indicates the total seconds of the time difference
  
  // Define the Ukrainian language strings
  const strings = {
    seconds: 'менше хвилини',
    minute: 'хвилину',
    minutes: '%d хвилин',
    hour: 'годину',
    hours: '%d годин',
    day: 'день',
    days: '%d днів',
    month: 'місяць',
    months: '%d місяців',
    year: 'рік',
    years: '%d років',
  };

  // Return the corresponding string based on the unit index and value
  if (index === 0) {
    return strings.seconds;
  } else if (index === 1) {
    return strings.minute;
  } else if (index === 2) {
    return strings.minutes.replace('%d', number);
  } else if (index === 3 || index === 4) {
    return strings.hours.replace('%d', number);
  } else if (index === 5 || index === 6) {
    return strings.days.replace('%d', number);
  } else if (index === 7 || index === 8) {
    return strings.months.replace('%d', number);
  } else if (index === 9 || index === 10) {
    return strings.years.replace('%d', number);
  }
}
